
import { Pencil, Plus } from "lucide-react";
import React from "react";
import { getBrand } from "@/api_call/api";
import Link from "next/link";
import DeleteBtn from "@/app/components/admin components/DeleteBtn";

export default async function UserManagementTable() {
  
  const data  = await getBrand();
  // console.log(data)
  // return
  
  const Brands = data.data;
  console.log(Brands.categoryId)
  const meta = data.meta;
  console.log(meta)
  return (
    <div className="p-6min-h-screen">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-3xl font-semibold text-gray-800">
            Brand
          </h1>
          <p className="text-sm text-gray-500 mt-1">
            Manage Brands 
          </p>
        </div>

        <Link href={"brand/addBrand"}>
          <button className="flex items-center gap-2 px-5 py-2.5 bg-orange-500 text-white rounded-xl shadow hover:shadow-md hover:scale-105 transition">
            <Plus size={18} />
            Add Brand
          </button>
        </Link>
      </div>

      {/* Table Container */}
      <div className="bg-white rounded-2xl shadow-2xl overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full text-left">
            {/* Table Head */}
            <thead className="bg-gray-100 border-b">
              <tr>
                <th className="px-2 py-4 text-sm font-semibold text-gray-600 uppercase tracking-wide">
                  Image
                </th>
                <th className="px-2 py-4 text-sm font-semibold text-gray-600 uppercase tracking-wide">
                  Brand Name
                </th>
                <th className="px-2 py-4 text-sm font-semibold text-gray-600 uppercase tracking-wide">
                  Slug
                </th>
                <th className="px-2 py-4 text-sm font-semibold text-gray-600 uppercase tracking-wide">
                  Category
                </th>
                <th className="px-2 py-4 text-sm font-semibold text-gray-600 uppercase tracking-wide">
                  Actions
                </th>
              </tr>
            </thead>

            {/* Table Body */}
            <tbody>
              {Brands.map((user, index) => (
                <tr
                  key={index}
                  className="border-b hover:bg-gray-50 transition"
                >
                  {/* Image */}
                  <td className="px-2 py-4">
                    <img
                      src={`http://localhost:5000/brand/${user?.image}`}
                      alt={user.name}
                      className="w-12 h-12 rounded-lg object-cover"
                    />
                  </td>

                  {/* Name */}
                  <td className="px-2 py-4 font-medium text-gray-800">
                    {user.name}
                  </td>

                  {/* Slug */}
                  <td className="px-2 py-4 text-gray-500">{user.slug}</td>
                  <td className="px-2 py-4 text-gray-500">Your category</td>

                  

                  {/* Actions */}
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-4">
                      <button className="p-2 rounded-lg hover:bg-blue-50 text-blue-600 hover:text-blue-800 transition">
                        <Link href={`/admin/category/edit/${user.slug}`}>
                        <Pencil size={18} />
                        </Link>
                      </button>

                      <DeleteBtn id={user._id} />
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
